1	type Rover = { x: number; y: number; heading: string };
2	
3	const forwardDelta: Record<string, { dx: number; dy: number }> = {
4	  N: { dx: 0, dy: 1 },
5	  E: { dx: 1, dy: 0 },
6	  S: { dx: 0, dy: -1 },
7	  W: { dx: -1, dy: 0 },
8	};
9	
10	const leftTurn: Record<string, string> = {
11	  N: "W",
12	  W: "S",
13	  S: "E",
14	  E: "N",
15	};
16	
17	const rightTurn: Record<string, string> = {
18	  N: "E",
19	  E: "S",
20	  S: "W",
21	  W: "N",
22	};
23	
24	const commandHandlers: Record<string, (rover: Rover) => Rover> = {
25	  F: (rover) => {
26	    const { dx, dy } = forwardDelta[rover.heading];
27	    return { ...rover, x: rover.x + dx, y: rover.y + dy };
28	  },
29	  L: (rover) => ({ ...rover, heading: leftTurn[rover.heading] }),
30	  R: (rover) => ({ ...rover, heading: rightTurn[rover.heading] }),
31	};
32	
33	export function moveRover(rover: Rover, commands: string): Rover {
34	  const handler = commandHandlers[commands];
35	  return handler ? handler(rover) : rover;
36	}
